    author: 'Air Fresh Marketing Team',
    date: 'April 20, 2026',
    readTime: '9 min read',
    category: 'Industry Guides',
    tags: ['beverage brands', 'energy drinks', 'sampling programs', 'RTD cocktails', 'beverage marketing']
